// File: tls_inspect.dart
// Run: dart tls_inspect.dart github.com
import 'dart:io';

void main(List<String> args) async {
  final host = args.isNotEmpty ? args[0] : 'example.com';

  print('--- TLS handshake to $host ---');
  final t0 = DateTime.now();
  final socket = await SecureSocket.connect(host, 443,
      onBadCertificate: (cert) {
        print('BAD CERT! Refusing. subject=${cert.subject}');
        return false;    // never accept bad certs in real code
      });
  final ms = DateTime.now().difference(t0).inMilliseconds;
  print('TLS connected in $ms ms');

  final cert = socket.peerCertificate!;
  print('\n--- Server certificate ---');
  print('Subject : ${cert.subject}');
  print('Issuer  : ${cert.issuer}');
  print('Valid   : ${cert.startValidity}  →  ${cert.endValidity}');

  final now = DateTime.now();
  final daysLeft = cert.endValidity.difference(now).inDays;
  if (daysLeft < 30) {
    print('  ⚠️  Expires in $daysLeft days!');
  } else {
    print('  ✅  Valid for another $daysLeft days.');
  }

  socket.write('GET / HTTP/1.1\r\nHost: $host\r\nConnection: close\r\n\r\n');
  final all = await socket.fold<List<int>>([], (a,b)=>a..addAll(b));
  print('\nGot ${all.length} bytes of encrypted-then-decrypted HTTP response.');
  await socket.close();
}

// Typical output:
// --- TLS handshake to github.com ---
// TLS connected in 143 ms
// --- Server certificate ---
// Subject : /CN=github.com
// Issuer  : /C=US/O=DigiCert Inc/OU=www.digicert.com/CN=DigiCert TLS Hybrid ECC SHA384 2020 CA1
// Valid   : 2026-02-14  →  2027-03-14
//   ✅  Valid for another 256 days.
// Got 1187 bytes of encrypted-then-decrypted HTTP response.
